import { useState, useEffect } from "react";

function Movies() {
  const [movies, setMovies] = useState(() => {
    const saved = localStorage.getItem("movies");
    return saved
      ? JSON.parse(saved)
      : [
          { title: "Inception", rating: 9 },
          { title: "Interstellar", rating: 8 },
          { title: "Titanic", rating: 7 },
          { title: "Avatar", rating: 8 },
          { title: "Joker", rating: 9 },
          { title: "Batman", rating: 8 },
          { title: "Spider-Man", rating: 7 },
          { title: "Avengers", rating: 9 },
          { title: "Frozen", rating: 6 },
          { title: "Cars", rating: 6 },
        ];
  });

  const [search, setSearch] = useState("");
  const [sort, setSort] = useState("");
  const [newTitle, setNewTitle] = useState("");
  const [newRating, setNewRating] = useState("");

  useEffect(() => {
    localStorage.setItem("movies", JSON.stringify(movies));
  }, [movies]);

  const addMovie = () => {
    if (newTitle.trim() === "" || newRating === "") {
      alert("Fill all fields");
      return;
    }

    if (newRating < 1 || newRating > 10) {
      alert("Rating must be 1-10");
      return;
    }

    setMovies([...movies, { title: newTitle, rating: Number(newRating) }]);
    setNewTitle("");
    setNewRating("");
  };

  const deleteMovie = (index) => {
    setMovies(movies.filter((_, i) => i !== index));
  };

  return (
    <div>
      <h2>Movies 🎬</h2>

      <input
        type="text"
        placeholder="Search..."
        onChange={(e) => setSearch(e.target.value)}
      />

      <select onChange={(e) => setSort(e.target.value)}>
        <option value="">Default</option>
        <option value="asc">Low → High</option>
        <option value="desc">High → Low</option>
      </select>

      <div>
        <input
          type="text"
          placeholder="Movie name"
          value={newTitle}
          onChange={(e) => setNewTitle(e.target.value)}
        />

        <input
          type="number"
          placeholder="Rating"
          value={newRating}
          min="1"
          max="10"
          onChange={(e) => setNewRating(e.target.value)}
        />

        <button onClick={addMovie}>Add</button>
      </div>

      <ul>
        {movies
          .filter((m) =>
            m.title.toLowerCase().includes(search.toLowerCase())
          )
          .sort((a, b) => {
            if (sort === "asc") return a.rating - b.rating;
            if (sort === "desc") return b.rating - a.rating;
            return 0;
          })
          .map((movie, i) => (
            <li key={i}>
              {movie.title} ⭐ {movie.rating}
              <button onClick={() => deleteMovie(i)}>❌</button>
            </li>
          ))}
      </ul>
    </div>
  );
}

export default Movies;
